window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["asbestos"] = window.COURSE_LANG["asbestos"] || {};
window.COURSE_LANG["asbestos"]["es"] = [
  {"id":1,"q":"El asbesto se describe mejor como:","opts":["Una fibra plástica artificial","Un mineral fibroso de origen natural","Un tipo de aislamiento de fibra de vidrio","Una espuma sintética"],"re":"El asbesto es un grupo de minerales fibrosos de origen natural que en el pasado se valoraban por su resistencia al calor y al fuego."},
  {"id":2,"q":"El asbesto se usó ampliamente en la construcción principalmente porque es:","opts":["Resistente al fuego, fuerte y un buen aislante","Liviano y transparente","Conductor de electricidad","Solo impermeable y flexible"],"re":"Resiste el calor y el fuego, aporta resistencia y aísla bien, por lo cual era común antes de la década de 1980."},
  {"id":3,"q":"¿Qué hace que el asbesto sea peligroso para la salud?","opts":["Su color","Se rompe en fibras microscópicas que se pueden inhalar","Es radiactivo","Se disuelve en agua"],"re":"Cuando se altera, el asbesto libera fibras diminutas que se alojan en lo profundo de los pulmones."},
  {"id":4,"q":"El material que contiene asbesto 'friable' es aquel que:","opts":["Está sellado en concreto","Se puede desmenuzar con la presión de la mano, liberando fibras","Siempre es seguro de retirar","No contiene fibras"],"re":"El material friable se desmenuza con la presión de la mano y libera fibras con facilidad, siendo la forma más peligrosa."},
  {"id":5,"q":"¿Se puede saber si un material contiene asbesto con solo mirarlo?","opts":["Sí, por su color","Sí, por su olor","No; solo el análisis de laboratorio puede confirmarlo","Sí, si tiene más de 50 años"],"re":"Solo las pruebas de laboratorio (por ejemplo, microscopía de luz polarizada) confirman el asbesto; suponga que los materiales sospechosos contienen asbesto hasta que se prueben."},
  {"id":6,"q":"¿Cuál de los siguientes es un tipo común de asbesto?","opts":["Crisotilo (blanco)","Polietileno","Celulosa","Perlita"],"re":"El crisotilo (asbesto blanco) es el tipo más común usado en los edificios; la amosita y la crocidolita son otros."},
  {"id":7,"q":"Según Cal/OSHA, un material generalmente se considera 'que contiene asbesto' cuando contiene más de:","opts":["0.01% de asbesto","0.1% de asbesto","1% de asbesto","10% de asbesto"],"re":"Cal/OSHA considera que un material con más de 0.1% de asbesto contiene asbesto (la EPA/NESHAP federal usa 1%)."},
  {"id":8,"q":"El material de asbesto no friable (por ejemplo, una baldosa de piso intacta) se vuelve peligroso principalmente cuando se:","opts":["Deja sin alterar","Pinta encima","Corta, lija, perfora o rompe","Limpia con agua"],"re":"El material no friable presenta bajo riesgo cuando está intacto, pero libera fibras cuando se corta, lija, perfora o rompe."},
  {"id":9,"q":"La suposición más segura sobre un material sospechoso en un edificio anterior a 1980 es:","opts":["Suponer que está libre de asbesto","Suponer que contiene asbesto hasta que se pruebe","Ignorarlo","Quemar una muestra para verificar"],"re":"Trate los materiales sospechosos en edificios antiguos como si contuvieran asbesto hasta que los resultados de laboratorio demuestren lo contrario."},
  {"id":10,"q":"La principal forma en que las fibras de asbesto ingresan al cuerpo es por:","opts":["Absorción por la piel","Inhalación de fibras suspendidas en el aire","Beber agua","Contacto con los ojos"],"re":"La inhalación de fibras suspendidas en el aire es la principal vía de exposición y daño."},
  {"id":11,"q":"¿Qué enfermedad es causada casi exclusivamente por la exposición al asbesto?","opts":["Mesotelioma","El resfriado común","Diabetes","Tendinitis"],"re":"El mesotelioma, cáncer del revestimiento de los pulmones o del abdomen, está estrechamente vinculado al asbesto."},
  {"id":12,"q":"La asbestosis es:","opts":["Una erupción cutánea","Cicatrización del tejido pulmonar por fibras inhaladas","Un tipo de dolor de cabeza","Una infección bacteriana"],"re":"La asbestosis es una cicatrización crónica (fibrosis) de los pulmones que dificulta la respiración."},
  {"id":13,"q":"Los síntomas de la enfermedad relacionada con el asbesto suelen aparecer:","opts":["En cuestión de horas","En el plazo de una semana","Muchos años después (a menudo 10 a 40) de la exposición","Solo en niños"],"re":"Las enfermedades por asbesto tienen un periodo de latencia prolongado; a menudo pasan décadas antes de que se manifiesten los síntomas."},
  {"id":14,"q":"Combinar el tabaquismo con la exposición al asbesto:","opts":["No tiene efecto sobre el riesgo","Multiplica enormemente el riesgo de cáncer de pulmón","Anula el peligro","Solo afecta a los no fumadores"],"re":"El tabaquismo y el asbesto actúan juntos de forma sinérgica, aumentando drásticamente el riesgo de cáncer de pulmón."},
  {"id":15,"q":"¿Cuál es el nivel 'seguro' establecido de exposición al asbesto?","opts":["10 fibras/cc","1 fibra/cc","No hay ningún nivel comprobado como completamente seguro; reduzca al mínimo toda exposición","Cualquier nivel por debajo del punto de ebullición"],"re":"No se ha comprobado que ningún nivel de exposición sea completamente seguro; el objetivo es mantener la exposición lo más baja posible."},
  {"id":16,"q":"El asbesto representa el mayor riesgo para la salud cuando:","opts":["Está encapsulado e intacto","Sus fibras quedan suspendidas en el aire y se inhalan","Está húmedo y sin alterar","Está enterrado en un vertedero"],"re":"El riesgo es máximo cuando el material se altera y las fibras quedan suspendidas en el aire para ser inhaladas."},
  {"id":17,"q":"Por lo general, se exige que los trabajadores que alteran el asbesto cuenten con:","opts":["Ninguna medida especial","Vigilancia médica y protección respiratoria","Solo guantes","Solo una licencia comercial"],"re":"Cal/OSHA exige vigilancia médica, capacitación y protección respiratoria para el trabajo con asbesto."},
  {"id":18,"q":"Es más probable que se encuentre asbesto en edificios construidos:","opts":["Después de 2010","Antes de aproximadamente 1980","Solo después de 2000","Solo en la década de 1990"],"re":"El uso del asbesto era común antes de aproximadamente 1980; los edificios más antiguos son la principal preocupación."},
  {"id":19,"q":"¿Cuál de estos materiales antiguos contenía comúnmente asbesto?","opts":["Aislamiento de tuberías y calderas","Bombillas LED","Conducto de PVC","Revestimiento de aluminio"],"re":"El aislamiento térmico de tuberías y calderas ('lagging') era un producto clásico de asbesto."},
  {"id":20,"q":"La antigua textura de techo 'popcorn' o acústica puede contener:","opts":["Asbesto","Solo pintura con plomo","Cemento puro","Nada peligroso"],"re":"Los techos acústicos rociados ('popcorn') de épocas anteriores con frecuencia contienen asbesto."},
  {"id":21,"q":"La baldosa de piso de vinilo y el mástique negro debajo de ella en edificios antiguos pueden contener:","opts":["Asbesto","Solo cera","Solo caucho","Es imposible que haya asbesto en los pisos"],"re":"La baldosa de vinilo-asbesto de 9x9 y su adhesivo de mástique son fuentes de asbesto muy conocidas."},
  {"id":22,"q":"En los sistemas HVAC antiguos, el asbesto se usaba comúnmente en:","opts":["Aislamiento/envoltura de conductos y juntas","Termostatos digitales","Líneas de cobre","Controles wifi"],"re":"La envoltura de conductos, la cinta y las juntas en los sistemas HVAC antiguos a menudo contienen asbesto, lo cual es relevante para los oficios de HVAC."},
  {"id":23,"q":"La tubería de cemento con asbesto (a menudo llamada 'Transite') se usaba para:","opts":["Tuberías de agua, alcantarillado y conductos","Cable de fibra óptica","Cableado eléctrico","Mangueras de jardín"],"re":"La tubería de cemento con asbesto Transite se usaba para aplicaciones de agua, alcantarillado y conductos/chimeneas de HVAC."},
  {"id":24,"q":"El compuesto para juntas y ciertas texturas de pared en edificios antiguos pueden contener:","opts":["Asbesto","Solo yeso, nunca asbesto","Solo pintura","Solo arena"],"re":"El compuesto para juntas de paneles de yeso y las texturas anteriores a 1980 pueden contener asbesto."},
  {"id":25,"q":"¿Cuál de estos también puede ser una fuente de asbesto en un techo?","opts":["Fieltros, tejas y mástiques de techado","Paneles solares","Canaletas de lluvia de vinilo","Solo membrana moderna"],"re":"Los fieltros, las tejas y los mástiques/cementos de tapajuntas de techado antiguos pueden contener asbesto."},
  {"id":26,"q":"En California, la agencia que regula la seguridad de los trabajadores en el trabajo con asbesto es:","opts":["La CSLB","Cal/OSHA (DOSH)","El DMV","La junta local de aguas"],"re":"Cal/OSHA (División de Seguridad y Salud Ocupacional) regula la seguridad de los trabajadores y el registro relacionados con el asbesto."},
  {"id":27,"q":"Un contratista debe registrarse ante Cal/OSHA para el trabajo con asbesto que involucre al menos:","opts":["1 pie cuadrado","10 pies cuadrados","100 pies cuadrados (o lineales) de material que contiene asbesto","10,000 pies cuadrados"],"re":"Se requiere el registro ante Cal/OSHA para el trabajo relacionado con asbesto que involucre 100 pies cuadrados/lineales o más."},
  {"id":28,"q":"Aprobar el examen de asbesto a libro abierto de la CSLB significa que usted:","opts":["Ya está certificado para retirar asbesto","Ha demostrado conocimiento básico; NO autoriza la remoción de asbesto","Puede omitir el registro ante Cal/OSHA","Está exento del examen del oficio"],"re":"El examen a libro abierto solo demuestra conocimiento; la remoción requiere el registro ante Cal/OSHA y la certificación adecuada."},
  {"id":29,"q":"¿Cuál clasificación de la CSLB es específicamente para la remoción de asbesto?","opts":["C-20","C-22 (Remoción de Asbesto)","C-36","B (Construcción General)"],"re":"La C-22 es la clasificación de Remoción de Asbesto; es independiente del examen a libro abierto."},
  {"id":30,"q":"El examen de asbesto a libro abierto se exige a los nuevos solicitantes de licencia según:","opts":["El Código de Negocios y Profesiones §7058.5","Solo la Ley de Aire Limpio","Ninguna ley; es opcional","Solo una ordenanza municipal"],"re":"El BPC §7058.5 exige la certificación de asbesto a libro abierto para los nuevos solicitantes."},
  {"id":31,"q":"¿Quién debe completar el examen de asbesto a libro abierto de la CSLB?","opts":["Todos los empleados","La persona calificadora (Qualifier) de la licencia","Solo el contador","Solo los subcontratistas"],"re":"La persona calificadora de la licencia rinde el examen de asbesto a libro abierto."},
  {"id":32,"q":"La agencia federal que establece las normas NESHAP para el asbesto en demolición/renovación es:","opts":["La EPA","El FBI","La FAA","El USPS"],"re":"La EPA administra la NESHAP, que rige el manejo del asbesto en la demolición y la renovación."},
  {"id":33,"q":"Antes de una demolición o renovación que pueda alterar el asbesto, la NESHAP generalmente exige notificar a la agencia del aire:","opts":["Después de terminar el trabajo","Aproximadamente 10 días hábiles antes","Solo si se solicita","Nunca"],"re":"La NESHAP exige un aviso por escrito anticipado (aproximadamente 10 días hábiles) a la agencia del aire reguladora."},
  {"id":34,"q":"El Límite de Exposición Permisible (PEL) de Cal/OSHA para el asbesto durante una jornada de 8 horas es:","opts":["0.1 fibra por centímetro cúbico (f/cc)","10 f/cc","1 gramo por litro","No existe"],"re":"El PEL de Cal/OSHA como TWA de 8 horas es de 0.1 f/cc, con un límite de excursión a corto plazo de 1.0 f/cc."},
  {"id":35,"q":"Realizar legalmente una remoción de asbesto a gran escala generalmente requiere:","opts":["Solo una tarjeta de presentación","Registro ante Cal/OSHA más trabajadores capacitados/certificados","Solo un respirador","Nada especial"],"re":"La remoción legal requiere el registro ante Cal/OSHA, trabajadores capacitados y certificados y (para la clasificación) la C-22."},
  {"id":36,"q":"El examen de asbesto a libro abierto se presenta ante la CSLB:","opts":["Antes de presentar la solicitud","En la etapa de emisión de la licencia, junto con la fianza y la tarifa","Diez años después","Solo si reprueba el examen del oficio"],"re":"Se presenta en el momento de la emisión, junto con la fianza del contratista y la tarifa de la licencia."},
  {"id":37,"q":"La forma preferida de controlar la liberación de fibras durante la remoción de asbesto es:","opts":["Usar aire comprimido","Mantener el material húmedo (métodos húmedos)","Barrerlo en seco rápidamente","Usar un ventilador doméstico"],"re":"Humedecer suprime las fibras suspendidas en el aire y es el método de control fundamental."},
  {"id":38,"q":"¿Cuál práctica está PROHIBIDA al manipular asbesto?","opts":["Humedecer el material","Usar una aspiradora HEPA","Usar aire comprimido o barrer en seco","Embolsar los desechos"],"re":"El aire comprimido y el barrido en seco dispersan las fibras en el aire y están prohibidos."},
  {"id":39,"q":"La aspiradora correcta para la limpieza de asbesto es:","opts":["Cualquier aspiradora de taller","Una aspiradora con filtro HEPA","Un soplador de hojas","Una aspiradora de líquidos y sólidos sin filtro"],"re":"Solo las aspiradoras con filtro HEPA capturan las fibras diminutas; las aspiradoras comunes las dispersan."},
  {"id":40,"q":"Los desechos de asbesto deben:","opts":["Tirarse en cualquier contenedor de basura","Humedecerse, sellarse en recipientes herméticos etiquetados y llevarse a un vertedero aprobado","Quemarse en el sitio","Reciclarse con el metal"],"re":"Los desechos de asbesto se humedecen, se sellan/embolsan por partida doble, se etiquetan y se desechan en un sitio aprobado."},
  {"id":41,"q":"La protección respiratoria para el trabajo con asbesto debe ser:","opts":["Una mascarilla de papel para polvo","Un respirador aprobado y debidamente ajustado (por ejemplo, HEPA/presión negativa)","Un paño húmedo","Opcional"],"re":"Se requieren respiradores aprobados y con prueba de ajuste (HEPA / presión negativa); las mascarillas de papel no califican."},
  {"id":42,"q":"Para los trabajos de remoción a gran escala, las fibras se contienen mediante:","opts":["Una ventana abierta","Un recinto de presión negativa con filtración HEPA","Un ventilador de caja","Sin contención"],"re":"Un recinto sellado de presión negativa con filtración HEPA impide que las fibras se escapen."},
  {"id":43,"q":"Los trajes y la ropa desechables usados en la remoción deben:","opts":["Llevarse a casa y lavarse","Tratarse como desechos de asbesto y desecharse adecuadamente","Reutilizarse la próxima semana","Venderse"],"re":"Los desechables contaminados son desechos de asbesto; nunca se reutilizan ni se llevan a casa."},
  {"id":44,"q":"¿Por qué se debe mantener húmedo el material de asbesto durante la remoción?","opts":["Para hacerlo más pesado al levantarlo","Porque humedecerlo suprime la liberación de fibras en el aire","Para limpiar el piso","No es necesario"],"re":"El agua impide que las fibras queden suspendidas en el aire, que es la principal vía de exposición."},
  {"id":45,"q":"Los recipientes de desechos de asbesto deben:","opts":["Estar sin marcar","Estar etiquetados con las etiquetas de advertencia de asbesto adecuadas","Pintarse de verde","Dejarse abiertos"],"re":"Las regulaciones exigen etiquetas de advertencia de asbesto en los recipientes sellados de desechos."},
  {"id":46,"q":"Si encuentra inesperadamente material sospechoso de contener asbesto durante un trabajo, debe:","opts":["Seguir trabajando más rápido","Detener el trabajo y hacer que se pruebe antes de alterarlo","Barrerlo de inmediato","Pintar encima"],"re":"Deténgase, aísle el área y haga pruebas antes de cualquier alteración adicional."},
  {"id":47,"q":"Después de la remoción, la autorización del aire del área normalmente se confirma mediante:","opts":["El lanzamiento de una moneda","Monitoreo/muestreo del aire que muestre fibras por debajo del nivel de autorización","Solo mirar alrededor","El olor"],"re":"El muestreo de aire de autorización confirma que los niveles de fibras son lo suficientemente bajos antes de volver a ocupar el área."}
];
